using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    // ---------- CreateOrder – happy paths ----------

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        var items = MakeItems(("Widget", 10m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithNonEmptyId()
    {
        var items = MakeItems(("Widget", 10m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_CalculatesTotalCorrectly()
    {
        var items = MakeItems(("A", 5m, 3), ("B", 12.50m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(5m * 3 + 12.50m * 2, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = MakeItems(("Widget", 1m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        var items = MakeItems(("Widget", 10m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_ProducesUniqueIds()
    {
        var items = MakeItems(("Widget", 1m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // ---------- CreateOrder – validation ----------

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = MakeItems(("Widget", 10m, 1));

        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _sut.CreateOrder("cust-1", []));
    }

    // ---------- GetOrder ----------

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var created = _sut.CreateOrder("cust-1", MakeItems(("Widget", 5m, 1)));

        var found = _sut.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistingId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ---------- GetOrdersByCustomer ----------

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllMatchingOrders()
    {
        _sut.CreateOrder("cust-1", MakeItems(("A", 1m, 1)));
        _sut.CreateOrder("cust-1", MakeItems(("B", 2m, 1)));
        _sut.CreateOrder("cust-2", MakeItems(("C", 3m, 1)));

        var orders = _sut.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        _sut.CreateOrder("cust-1", MakeItems(("A", 1m, 1)));

        var orders = _sut.GetOrdersByCustomer("cust-999");

        Assert.AreEqual(0, orders.Count);
    }

    // ---------- helpers ----------

    private static List<OrderItem> MakeItems(params (string Name, decimal Price, int Qty)[] entries) =>
        entries.Select(e => new OrderItem
        {
            ProductName = e.Name,
            Price = e.Price,
            Quantity = e.Qty
        }).ToList();
}

